from altalpha import DataClient
from lean import Algorithm

class FootTrafficAlpha(Algorithm):
    def initialize(self):
        self.set_start_date(2020, 1, 1)
        self.set_cash(1_000_000)
        self.alt = DataClient(api_key="YOUR_KEY")
        self.universe = ["WMT", "TGT", "COST", "HD", "LOW"]
        for ticker in self.universe:
            self.add_equity(ticker)

    def on_data(self, data):
        for ticker in self.universe:
            traffic = self.alt.query(
                dataset="orbital-insight/foot-traffic",
                filters={"ticker": ticker, "date": self.time.date().isoformat()},
            )
            if traffic.empty:
                continue
            yoy = traffic["visit_count_yoy"].mean()
            if yoy > 0.05:
                self.set_holdings(ticker, 1.0 / len(self.universe))
            elif yoy < -0.05:
                self.liquidate(ticker)
